1	import { ensureSchema } from "./schema.mjs";
2	
3	export async function createAccounts(db, data) {
4	  await ensureSchema(db);
5	  const doc = { ...data, createdAt: data.createdAt || new Date() };
6	  const result = await db.collection("accounts").insertOne(doc);
7	  return { _id: result.insertedId, ...doc };
8	}
9	
10	export async function getAccounts(db, id) {
11	  return db.collection("accounts").findOne({ accountId: id });
12	}
13	
14	export async function updateAccounts(db, id, data) {
15	  await db.collection("accounts").updateOne({ accountId: id }, { $set: data });
16	  return db.collection("accounts").findOne({ accountId: id });
17	}
18	
19	export async function deleteAccounts(db, id) {
20	  const result = await db.collection("accounts").deleteOne({ accountId: id });
21	  return result.deletedCount > 0;
22	}
